// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdbool.h>

typedef struct Node {
    int val;
    struct Node *left, *right;
} Node;

typedef struct BSTIterator {
    Node **stack;
    int top;
    int capacity;
} BSTIterator;

Node* newNode(int v) {
    Node* n = (Node*)malloc(sizeof(Node));
    n->val = v; n->left = n->right = NULL;
    return n;
}

Node* buildTree(int *arr, int n) {
    if (n == 0 || arr[0] == -1) return NULL;
    Node **nodes = (Node**)calloc(n, sizeof(Node*));
    for (int i = 0; i < n; ++i) if (arr[i] != -1) nodes[i] = newNode(arr[i]);
    for (int i = 0; i < n; ++i) if (nodes[i]) {
        int l = 2*i + 1, r = 2*i + 2;
        if (l < n) nodes[i]->left = nodes[l];
        if (r < n) nodes[i]->right = nodes[r];
    }
    Node* root = nodes[0];
    free(nodes);
    return root;
}

BSTIterator* iteratorCreate(Node* root) {
    BSTIterator* it = (BSTIterator*)malloc(sizeof(BSTIterator));
    it->capacity = 1000;
    it->stack = (Node**)malloc(it->capacity * sizeof(Node*));
    it->top = -1;
    Node* cur = root;
    while (cur) {
        if (it->top + 1 == it->capacity) {
            it->capacity *= 2;
            it->stack = (Node**)realloc(it->stack, it->capacity * sizeof(Node*));
        }
        it->stack[++it->top] = cur;
        cur = cur->left;
    }
    return it;
}

int iteratorNext(BSTIterator* it) {
    Node* node = it->stack[it->top--];
    int ret = node->val;
    Node* cur = node->right;
    while (cur) {
        if (it->top + 1 == it->capacity) {
            it->capacity *= 2;
            it->stack = (Node**)realloc(it->stack, it->capacity * sizeof(Node*));
        }
        it->stack[++it->top] = cur;
        cur = cur->left;
    }
    return ret;
}

bool iteratorHasNext(BSTIterator* it) {
    return it->top >= 0;
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int *arr = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) scanf("%d", &arr[i]);
        Node* root = buildTree(arr, N);
        free(arr);
        // read the rest of the line after the last integer
        char buffer[1024];
        scanf("%*c"); // consume newline
        fgets(buffer, sizeof(buffer), stdin);
        // tokenise
        char *token = strtok(buffer, " \n\r");
        BSTIterator* it = NULL;
        int first = 1;
        while (token) {
            if (strcmp(token, "BSTIterator") == 0) {
                if (it) { free(it->stack); free(it); }
                it = iteratorCreate(root);
                if (!first) printf(" ");
                printf("null");
                first = 0;
            } else if (strcmp(token, "next") == 0) {
                int v = iteratorNext(it);
                if (!first) printf(" ");
                printf("%d", v);
                first = 0;
            } else if (strcmp(token, "hasNext") == 0) {
                bool b = iteratorHasNext(it);
                if (!first) printf(" ");
                printf(b ? "true" : "false");
                first = 0;
            }
            token = strtok(NULL, " \n\r");
        }
        printf("\n");
        // free tree
        // (omitted for brevity, judge process ends soon)
        if (it) { free(it->stack); free(it); }
    }
    return 0;
}

