// COMPLETE, COMPILABLE C++ code
#include <bits/stdc++.h>
using namespace std;
struct Node {
    int val; Node *left, *right;
    Node(int v): val(v), left(nullptr), right(nullptr) {}
};
struct BSTIterator {
    vector<Node*> st;
    BSTIterator(Node* root) { pushLeft(root); }
    void pushLeft(Node* cur) { while (cur) { st.push_back(cur); cur = cur->left; } }
    int next() { Node* node = st.back(); st.pop_back(); int ans = node->val; pushLeft(node->right); return ans; }
    bool hasNext() const { return !st.empty(); }
};
Node* buildTree(const vector<int>& a) {
    int n = a.size();
    if (n==0 || a[0]==-1) return nullptr;
    vector<Node*> nodes(n,nullptr);
    for (int i=0;i<n;++i) if (a[i]!=-1) nodes[i]=new Node(a[i]);
    for (int i=0;i<n;++i) if (nodes[i]) {
        int l=2*i+1, r=2*i+2;
        if (l<n) nodes[i]->left = nodes[l];
        if (r<n) nodes[i]->right = nodes[r];
    }
    return nodes[0];
}
