            }else if(op=="next"){
                int v = it->next();
                if(!first) cout<<' ';
                cout<<v;
                first=false;
            }else if(op=="hasNext"){
                bool b = it->hasNext();
                if(!first) cout<<' ';
                cout<<(b?"true":"false");
                first=false;
            }
        }
